120	function getProvisioningSummary(slackId, clawName) {
121	  try {
122	    const statusOutput = runAdminCommand(
123	      `node bin/nemoclaw.js user-status '${sh(slackId)}'`,
124	      120000
125	    ).trim();
126	    return statusOutput.slice(-2500) || "(no status output)";
127	  } catch (err) {
128	    const output = `${err.stdout || ""}${err.stderr || ""}`.trim() || err.message;
129	    return `Status verification failed for ${clawName}:\n${output.slice(-2500)}`;
