        "```",
        "",
        "*resilience output*",
        "```",
        resilienceOutput.trim().slice(-2500) || "(no output)",
        "```",
        "",
        "*verification*",
        "```",
        statusSummary,
        "```",
      ].join("\n"),
    };
  } catch (err) {
    const output = `${err.stdout || ""}${err.stderr || ""}`.trim() || err.message;
    auditAdminAction(user, "add-claw", { slackId, displayName, clawName, githubHandle }, "failed", output.slice(0, 1000));
